INSERT INTO email_templates (tipo, lingua, oggetto, corpo_html) VALUES (
'conferma', 'it',
'Conferma il tuo account — Liberiamo la mente',
'<!DOCTYPE html><html lang="it"><head><meta charset="UTF-8"/><meta name="viewport" content="width=device-width,initial-scale=1.0"/></head><body style="margin:0;padding:0;background-color:#0a0a0f;font-family:Georgia,serif;"><table width="100%" cellpadding="0" cellspacing="0" style="background-color:#0a0a0f;padding:40px 20px;"><tr><td align="center"><table width="600" cellpadding="0" cellspacing="0" style="max-width:600px;width:100%;background-color:#0f0f1a;border:1px solid rgba(0,210,255,0.2);"><tr><td style="padding:40px 40px 30px;border-bottom:1px solid rgba(0,210,255,0.15);text-align:center;"><img src="https://liberiamo2076.com/logo-liberiamo.jpg" alt="Liberiamo la mente" width="80" height="80" style="display:block;margin:0 auto 20px;object-fit:cover;"/><div style="font-family:monospace;font-size:10px;letter-spacing:0.3em;color:rgba(0,210,255,0.6);text-transform:uppercase;margin-bottom:8px;">// trasmissione_in_arrivo · 2076</div><div style="font-size:28px;color:#f0ebe0;letter-spacing:-0.02em;line-height:1.2;">Liberiamo <span style="color:#00d2ff;">la mente</span></div></td></tr><tr><td style="padding:40px;"><p style="font-size:11px;font-family:monospace;letter-spacing:0.25em;color:rgba(0,210,255,0.7);text-transform:uppercase;margin:0 0 20px;">// conferma_account</p><h1 style="font-size:26px;color:#f0ebe0;margin:0 0 16px;font-weight:normal;line-height:1.3;">Benvenuto nella biblioteca.</h1><p style="font-size:16px;color:rgba(240,235,224,0.7);line-height:1.7;margin:0 0 24px;">Hai creato il tuo account su <strong style="color:#f0ebe0;">liberiamo2076.com</strong>.<br/>Per attivarlo e iniziare a leggere, clicca il pulsante qui sotto.</p><table cellpadding="0" cellspacing="0" style="margin:32px 0;"><tr><td style="background-color:rgba(0,210,255,0.1);border:1px solid #00d2ff;"><a href="{{CONFIRMATION_URL}}" style="display:block;padding:16px 40px;font-family:monospace;font-size:12px;letter-spacing:0.22em;text-transform:uppercase;color:#00d2ff;text-decoration:none;">▸ Conferma il tuo account</a></td></tr></table><p style="font-size:13px;color:rgba(240,235,224,0.4);line-height:1.6;margin:0 0 8px;">Il link è valido per <strong style="color:rgba(240,235,224,0.6);">24 ore</strong>. Se non hai richiesto tu questa registrazione, ignora questa email.</p><div style="border-top:1px solid rgba(0,210,255,0.1);margin:32px 0;"></div><p style="font-size:11px;font-family:monospace;letter-spacing:0.25em;color:rgba(0,210,255,0.5);text-transform:uppercase;margin:0 0 16px;">// cosa_puoi_fare</p><table cellpadding="0" cellspacing="0" width="100%"><tr><td style="padding:8px 0;font-size:14px;color:rgba(240,235,224,0.65);"><span style="color:#00d2ff;margin-right:10px;">◆</span>Segnalibro automatico — riprendi da dove hai smesso</td></tr><tr><td style="padding:8px 0;font-size:14px;color:rgba(240,235,224,0.65);"><span style="color:#00d2ff;margin-right:10px;">◆</span>Vota per recuperare i libri nel Cestino degli Scritti Perduti</td></tr><tr><td style="padding:8px 0;font-size:14px;color:rgba(240,235,224,0.65);"><span style="color:#00d2ff;margin-right:10px;">◆</span>Lascia recensioni e commenti nella community</td></tr></table><div style="border-top:1px solid rgba(0,210,255,0.1);margin:32px 0;"></div><p style="font-size:12px;color:rgba(240,235,224,0.35);line-height:1.7;margin:0;">Per cancellare il tuo account scrivi a <a href="mailto:noreply@liberiamo2076.com" style="color:rgba(0,210,255,0.5);text-decoration:none;">noreply@liberiamo2076.com</a>.</p></td></tr><tr><td style="padding:24px 40px;border-top:1px solid rgba(0,210,255,0.1);text-align:center;"><p style="font-family:monospace;font-size:10px;letter-spacing:0.2em;color:rgba(240,235,224,0.25);text-transform:uppercase;margin:0;">© 2076 Liberiamo la mente · liberiamo2076.com</p></td></tr></table></td></tr></table></body></html>'
) ON CONFLICT (tipo, lingua) DO UPDATE SET oggetto = EXCLUDED.oggetto, corpo_html = EXCLUDED.corpo_html;

INSERT INTO email_templates (tipo, lingua, oggetto, corpo_html) VALUES (
'conferma', 'en',
